const body = $input.first().json.body;

if (!body.user_id || !body.profile) {
  throw new Error('Missing user_id or profile');
}

const profile = body.profile;

return [{
  json: {
    user_id: body.user_id,
    profile: profile,
    iteration: 0,
    resume_data: null,
    ats_score: 0,
    best_resume_data: null,
    best_score: -1
  }
}];

const data = $input.first().json;

const iteration = (data.iteration || 0) + 1;

// Track the best resume seen so far so we never ship a worse one
let bestScore = (data.best_score === undefined || data.best_score === null) ? -1 : data.best_score;
let bestResume = data.best_resume_data || null;
if (data.ats_score > bestScore) {
  bestScore = data.ats_score;
  bestResume = data.resume_data;
}

const needsRefinement = data.ats_score < 90 && iteration < 4;

return [{
  json: {
    user_id: data.user_id,
    profile: data.profile,
    resume_data: data.resume_data,
    ats_score: data.ats_score,
    score_breakdown: data.score_breakdown || {},
    suggestions: data.suggestions || [],
    missing_keywords: data.missing_keywords || [],
    iteration: iteration,
    needs_refinement: needsRefinement,
    best_resume_data: bestResume,
    best_score: bestScore
  }
}];

let isRefinement = false;
let prev = null;

try {
  prev = $('Check Score').first().json;
  isRefinement = prev && prev.iteration > 0;
} catch(e) {
  isRefinement = false;
}

const parseInput = $('Parse Input').first().json;

const schema = '{"full_name":"","summary":"","experience":[{"company":"","role":"","dates":"","bullets":[""]}],"education":[{"degree":"","field":"","institution":"","year":"","grade":""}],"skills":[""],"projects":[{"name":"","description":"","tech":"","github":""}],"achievements":[{"title":"","description":"","year":""}],"certifications":[{"name":"","issuer":"","year":"","credential_url":""}]}';

const rules = 'RULES: Start every experience and project bullet with a strong action verb (Built, Designed, Automated, Led, Reduced, Increased, Migrated, Optimized). Quantify EVERY bullet with a concrete number, percentage, time saved, or scale. Mirror the candidate skills as keywords naturally; do not keyword-stuff. Write a sharp 2-3 sentence summary. Include achievements and certifications when available.';

let userMessage = '';

if (isRefinement && prev) {
  userMessage = 'Improve this resume to raise its ATS score above 90. Current score: ' + prev.ats_score + '/100. Fix these specific weaknesses: ' + (prev.suggestions || []).join(' | ') + '. Missing keywords to weave in naturally: ' + (prev.missing_keywords || []).join(', ') + '. ' + rules + ' Current resume JSON: ' + JSON.stringify(prev.resume_data) + '. Return ONLY improved valid JSON with this exact structure: ' + schema;
} else {
  userMessage = 'Create a professional ATS-optimized resume for this candidate. Profile: ' + JSON.stringify(parseInput.profile) + '. ' + rules + ' Return ONLY valid JSON with this exact structure: ' + schema;
}

return [{
  json: {
    user_id: parseInput.user_id,
    profile: parseInput.profile,
    iteration: isRefinement ? (prev.iteration || 0) : 0,
    best_resume_data: isRefinement ? (prev.best_resume_data || null) : null,
    best_score: isRefinement ? (prev.best_score === undefined ? -1 : prev.best_score) : -1,
    systemMessage: 'You are an expert resume writer specializing in cloud engineering and DevOps roles. Always respond with valid JSON only, no markdown, no explanation, no code blocks.',
    userMessage: userMessage
  }
}];

// Deterministic, rule-based ATS scorer. No LLM grading, no fixed 85 fallback.
const data = $input.first().json;
const r = data.resume_data || {};

const WEAK_VERBS = ['worked','helped','responsible','assisted','involved','participated','handled','did','made','used','supported'];
const STRONG_VERBS = ['built','designed','architected','led','automated','reduced','increased','improved','deployed','implemented','migrated','optimized','developed','launched','scaled','delivered','engineered','orchestrated','streamlined','accelerated','spearheaded','created','managed','drove'];

const profileSkills = (data.profile && data.profile.skills ? data.profile.skills : []).map(s => String(s).toLowerCase());
const targetKeywords = Array.from(new Set(profileSkills));

function hasMetric(str) { return /\d/.test(String(str)); }
function firstWord(str) { return String(str).trim().split(/\s+/)[0].toLowerCase().replace(/[^a-z]/g, ''); }

const weaknesses = [];
const experience = Array.isArray(r.experience) ? r.experience : [];
const projects = Array.isArray(r.projects) ? r.projects : [];
const skills = Array.isArray(r.skills) ? r.skills : [];

const allBullets = [];
experience.forEach(e => (e.bullets || []).forEach(b => allBullets.push(b)));
projects.forEach(p => { if (p.description) String(p.description).split('.').filter(s => s.trim().length > 10).forEach(s => allBullets.push(s)); });

// 1. Keyword coverage (25)
const resumeText = JSON.stringify(r).toLowerCase();
const matchedKw = targetKeywords.filter(k => k && resumeText.includes(k));
const missingKw = targetKeywords.filter(k => k && !resumeText.includes(k));
const kwScore = targetKeywords.length ? Math.round((matchedKw.length / targetKeywords.length) * 25) : 18;
if (missingKw.length) weaknesses.push('Incorporate these keywords naturally: ' + missingKw.slice(0, 8).join(', '));

// 2. Action verbs (20)
let strongCount = 0, weakCount = 0;
allBullets.forEach(b => { const w = firstWord(b); if (STRONG_VERBS.includes(w)) strongCount++; else if (WEAK_VERBS.includes(w)) weakCount++; });
const verbScore = allBullets.length ? Math.round((strongCount / allBullets.length) * 20) : 10;
if (weakCount > 0) weaknesses.push(weakCount + ' bullet(s) start with weak verbs; begin each with a strong action verb (Built, Automated, Reduced).');

// 3. Quantified achievements (20)
const quantified = allBullets.filter(hasMetric).length;
const quantScore = allBullets.length ? Math.round((quantified / allBullets.length) * 20) : 8;
if (allBullets.length && quantified < allBullets.length) weaknesses.push((allBullets.length - quantified) + ' bullet(s) lack a metric; add numbers, %, time saved, or scale.');

// 4. Structure / sections (20)
let structScore = 0;
if (r.full_name) structScore += 2;
if (r.summary && r.summary.length > 30) structScore += 3; else weaknesses.push('Add a strong 2-3 sentence professional summary.');
if (experience.length) structScore += 5; else weaknesses.push('Add work experience.');
if (Array.isArray(r.education) && r.education.length) structScore += 3; else weaknesses.push('Add education.');
if (skills.length) structScore += 3; else weaknesses.push('Add a skills section.');
if (projects.length) structScore += 2; else weaknesses.push('Add at least one project.');
if (Array.isArray(r.achievements) && r.achievements.length) structScore += 1; else weaknesses.push('Add an Achievements section.');
if (Array.isArray(r.certifications) && r.certifications.length) structScore += 1; else weaknesses.push('Add a Certifications section.');
if (structScore > 20) structScore = 20;

// 5. Skills depth (15)
const skillScore = Math.min(15, Math.round((skills.length / 12) * 15));
if (skills.length < 8) weaknesses.push('List at least 8-12 relevant skills.');

const score = Math.max(0, Math.min(100, kwScore + verbScore + quantScore + structScore + skillScore));

return [{
  json: {
    ...data,
    ats_score: score,
    score_breakdown: { keywords: kwScore, action_verbs: verbScore, achievements: quantScore, structure: structScore, skills: skillScore },
    suggestions: weaknesses,
    missing_keywords: missingKw
  }
}];

const data = $input.first().json;

const apiKey = 'your_api_key_here'; // your real key

const bodyObj = {
  model: 'nvidia/llama-3.3-nemotron-super-49b-v1.5',
  messages: [
    { role: 'system', content: data.systemMessage },
    { role: 'user', content: data.userMessage }
  ],
  temperature: 0.6,
  top_p: 0.95,
  max_tokens: 4096
};

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://integrate.api.nvidia.com/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + apiKey,
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  },
  body: JSON.stringify(bodyObj),
  returnFullResponse: false,
  ignoreHttpStatusErrors: false
});

const parsed = typeof response === 'string' ? JSON.parse(response) : response;
const choice = parsed.choices[0];

let rawContent = choice.message.content 
  || choice.message.reasoning_content 
  || choice.message.reasoning 
  || '';

if (!rawContent) {
  throw new Error('Empty response from model. Full response: ' + JSON.stringify(parsed));
}

const cleaned = rawContent
  .replace(/```json\n?/gi, '')
  .replace(/```\n?/gi, '')
  .trim();

const jsonStart = cleaned.indexOf('{');
const jsonEnd = cleaned.lastIndexOf('}');

if (jsonStart === -1 || jsonEnd === -1) {
  throw new Error('No JSON found in response: ' + cleaned.substring(0, 300));
}

const jsonString = cleaned.substring(jsonStart, jsonEnd + 1);

let resumeData;
try {
  resumeData = JSON.parse(jsonString);
} catch(e) {
  throw new Error('JSON parse failed: ' + jsonString.substring(0, 300));
}

return [{
  json: {
    user_id: data.user_id,
    profile: data.profile,
    resume_data: resumeData,
    iteration: data.iteration || 0,
    best_resume_data: data.best_resume_data || null,
    best_score: data.best_score === undefined ? -1 : data.best_score,
    ats_score: 0
  }
}];

const data = $input.first().json;

const supabaseUrl = "https://jxposfnuselsyjejjhte.supabase.co";
const serviceRoleKey = "your_service_role_key_here";

// Resolve user_id robustly: current item first, then fall back to the webhook input
let userId = data.user_id;
if (!userId) {
  try { userId = $('Webhook').first().json.body.user_id; } catch (e) {}
}
if (!userId) {
  try { userId = $('Parse Input').first().json.user_id; } catch (e) {}
}
if (!userId) {
  throw new Error('Could not resolve user_id from item, Webhook, or Parse Input');
}

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: supabaseUrl + '/rest/v1/resumes',
  headers: {
    'apikey': serviceRoleKey,
    'Authorization': 'Bearer ' + serviceRoleKey,
    'Content-Type': 'application/json',
    'Prefer': 'return=representation'
  },
  body: JSON.stringify({
    user_id: userId,
    type: 'base',
    s3_url: data.s3_url,
    ats_score: data.ats_score || 0,
    match_score: data.match_score || 0
  }),
  returnFullResponse: true,
  ignoreHttpStatusErrors: true
});

const parsed = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;

if (response.statusCode !== 201) {
  throw new Error('Supabase error ' + response.statusCode + ': ' + JSON.stringify(parsed));
}

return [{
  json: {
    success: true,
    user_id: userId,
    s3_url: data.s3_url,
    ats_score: data.ats_score || 0,
    match_score: data.match_score || 0
  }
}];

const bucketName = "resume-builder-pdfs-t2311";
const region = "ap-southeast-2";

const data = $input.first().json;

const userId = data.user_id;
const filename = data.filename;

const s3Url = `https://${bucketName}.s3.${region}.amazonaws.com/resumes/${userId}/${filename}`;

return [{
  json: {
    user_id: userId,
    s3_url: s3Url,
    ats_score: data.ats_score || 0,
    match_score: data.match_score || 0,
    filename: filename
  }
}];

const data = $input.first().json;

// Use the best resume produced across all iterations
const r = (data.best_score !== undefined && data.best_score >= data.ats_score && data.best_resume_data) ? data.best_resume_data : data.resume_data;
const finalScore = Math.max(data.ats_score || 0, data.best_score || 0);
const profile = data.profile || {};

function esc(str) {
  if (!str) return '';
  return String(str)
    .replace(/\\/g, '\\textbackslash{}')
    .replace(/&/g, '\\&')
    .replace(/%/g, '\\%')
    .replace(/\$/g, '\\$')
    .replace(/#/g, '\\#')
    .replace(/_/g, '\\_')
    .replace(/\{/g, '\\{')
    .replace(/\}/g, '\\}')
    .replace(/~/g, '\\textasciitilde{}')
    .replace(/\^/g, '\\textasciicircum{}');
}

const allSkills = r.skills || [];
const cloudSkills = allSkills.filter(s => ['aws','ec2','s3','iam','gcp','azure','terraform','cloud'].some(k => s.toLowerCase().includes(k)));
const containerSkills = allSkills.filter(s => ['docker','kubernetes','k8s','helm','argocd','container'].some(k => s.toLowerCase().includes(k)));
const cicdSkills = allSkills.filter(s => ['ci','cd','jenkins','github actions','gitlab','bash','shell','linux','git'].some(k => s.toLowerCase().includes(k)));
const monitorSkills = allSkills.filter(s => ['prometheus','grafana','monitor','elk','datadog','observ'].some(k => s.toLowerCase().includes(k)));
const otherSkills = allSkills.filter(s => ![...cloudSkills,...containerSkills,...cicdSkills,...monitorSkills].includes(s));

const experienceLatex = (r.experience || []).map(exp => `
\\resumeheading{${esc(exp.company)}}{${esc(profile.location || '')}}{${esc(exp.role)}}{${esc(exp.dates)}}
\\begin{resumeitem}
${(exp.bullets || []).map(b => `  \\item ${esc(b)}`).join('\n')}
\\end{resumeitem}
\\vspace{2pt}
`).join('\n');

const educationLatex = (r.education || []).map(edu => `
\\resumeheading{${esc(edu.institution)}}{${esc(profile.location || '')}}{${esc(edu.degree)} in ${esc(edu.field)}}{${esc(edu.year)}}
\\begin{flushleft}
\\vspace{-6pt}
${edu.grade ? `CGPA: ${esc(edu.grade)} \\\\` : ''}
\\end{flushleft}
`).join('\n');

const projectsLatex = (r.projects || []).map(p => {
  const bullets = (p.description || '').split('.').filter(s => s.trim().length > 10).map(s => `  \\item ${esc(s.trim())}.`).join('\n');
  return `
\\noindent\\textbf{${esc(p.name)}} \\hfill ${p.github ? `\\href{${esc(p.github)}}{\\textbf{[GitHub]}}` : ''}\\\\
\\noindent\\textit{Tech Stack: ${esc(p.tech)}} \\hfill \\\\
\\vspace{-4pt}
\\begin{resumeitem}
${bullets}
\\end{resumeitem}
\\vspace{4pt}
`;
}).join('\n');

const achievements = Array.isArray(r.achievements) ? r.achievements : [];
const achievementsLatex = achievements.length ? `\\section{Achievements}
\\begin{resumeitem}
${achievements.map(a => `  \\item \\textbf{${esc(a.title)}}${a.year ? ` (${esc(a.year)})` : ''}${a.description ? ` — ${esc(a.description)}` : ''}`).join('\n')}
\\end{resumeitem}` : '';

const certifications = Array.isArray(r.certifications) ? r.certifications : [];
const certificationsLatex = certifications.length ? `\\section{Certifications}
\\begin{resumeitem}
${certifications.map(c => `  \\item \\textbf{${esc(c.name)}}${c.issuer ? `, ${esc(c.issuer)}` : ''}${c.year ? ` (${esc(c.year)})` : ''}${c.credential_url ? ` \\href{${esc(c.credential_url)}}{[Verify]}` : ''}`).join('\n')}
\\end{resumeitem}` : '';

const latex = `\\documentclass[9pt,letterpaper]{article}
\\usepackage[utf8]{inputenc}
\\usepackage[margin=0.4in]{geometry}
\\usepackage{titlesec}
\\usepackage{enumitem}
\\usepackage{hyperref}
\\usepackage{nopageno}
\\usepackage{xcolor}
\\usepackage{fontawesome5}

\\definecolor{linkblue}{RGB}{20, 70, 160}
\\hypersetup{colorlinks=true,linkcolor=linkblue,urlcolor=linkblue}

\\pagestyle{empty}

\\titleformat{\\section}{\\large\\bfseries\\scshape}{}{0em}{}[\\titlerule]
\\titlespacing{\\section}{0pt}{6pt}{3pt}

\\newlist{resumeitem}{itemize}{1}
\\setlist[resumeitem]{label=$\\bullet$, leftmargin=12pt, topsep=1pt, itemsep=1pt, parsep=0pt}

\\newcommand{\\resumeheading}[4]{
    \\noindent\\textbf{#1} \\hfill #2\\\\
    \\noindent\\textit{#3} \\hfill \\textit{#4}\\vspace{1pt}
}

\\begin{document}

\\begin{center}
    {\\Huge \\textbf{\\textsc{${esc(r.full_name || profile.full_name || 'Name')}}}}\\\\
    \\vspace{3pt}
    ${esc(profile.location || '')} \\textbullet{} ${esc(profile.phone || '')} \\textbullet{} \\href{mailto:${esc(profile.email || '')}}{${esc(profile.email || '')}} \\\\
    \\vspace{4pt}
    ${profile.linkedin ? `\\href{https://${esc(profile.linkedin)}}{\\faLinkedin{} \\textbf{LinkedIn}} \\textbullet{}` : ''}
    ${profile.github ? `\\href{https://${esc(profile.github)}}{\\faGithub{} \\textbf{GitHub}}` : ''}
\\end{center}

${r.summary ? `\\section{Summary}
${esc(r.summary)}` : ''}

\\section{Education}
${educationLatex}

\\section{Technical Skills}
\\noindent \\textbf{Cloud \\& Infrastructure:} ${esc(cloudSkills.join(', '))} \\\\
\\textbf{Containerization \\& Orchestration:} ${esc(containerSkills.join(', '))} \\\\
\\textbf{CI/CD \\& Automation:} ${esc(cicdSkills.join(', '))} \\\\
\\textbf{Monitoring \\& Observability:} ${esc(monitorSkills.join(', '))} \\\\
${otherSkills.length > 0 ? `\\textbf{Other:} ${esc(otherSkills.join(', '))} \\\\` : ''}

\\section{Work Experience}
${experienceLatex}

\\section{Projects}
${projectsLatex}

${achievementsLatex}

${certificationsLatex}

\\end{document}`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://latex.ytotech.com/builds/sync',
  headers: {
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    compiler: 'pdflatex',
    resources: [
      {
        main: true,
        content: latex
      }
    ]
  }),
  returnFullResponse: true,
  ignoreHttpStatusErrors: true,
  encoding: 'arraybuffer'
});

if (response.statusCode !== 200 && response.statusCode !== 201) {
  let errMsg = '';
  try {
    errMsg = Buffer.from(response.body).toString('utf8').substring(0, 500);
  } catch(e) {}
  throw new Error('LaTeX compilation failed: ' + response.statusCode + ' — ' + errMsg);
}

const filename = `resume_${data.user_id}_${Date.now()}.pdf`;

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(response.body),
  filename,
  'application/pdf'
);

return [{
  json: {
    user_id: data.user_id,
    ats_score: finalScore,
    match_score: data.match_score || 0,
    filename: filename
  },
  binary: {
    data: binaryData
  }
}];
